import React from 'react';
// @ts-ignore ink types use exports field
import { Box, Text } from 'ink';

export interface CallRow {
  id: string;
  model: string;
  tokens: { input?: number; output?: number; total?: number };
  cost: number;
  agentLabel?: string;
  createdAt: string;
}

export interface CallTableProps {
  calls: CallRow[];
  avgCost: number;
}

export function CallTable({ calls, avgCost }: CallTableProps) {
  const visible = calls.slice(-15);
  return (
    <Box flexDirection="column" marginBottom={1}>
      <Text bold>📊 LLM Calls</Text>
      <Text dimColor>  {'Model'.padEnd(22)} {'Tokens'.padEnd(10)} {'Cost'.padEnd(10)} Agent</Text>
      {visible.map((c) => {
        const tokens = c.tokens?.total ?? 0;
        const hot = c.cost > avgCost * 2;
        return (
          <Text key={c.id} color={hot ? 'red' : undefined}>
            {'  '}{c.model.slice(0, 20).padEnd(22)} {String(tokens).padEnd(10)} ${c.cost.toFixed(4).padEnd(9)} {c.agentLabel ?? ''}
          </Text>
        );
      })}
      {calls.length === 0 && <Text dimColor>  Waiting for calls...</Text>}
    </Box>
  );
}
